import React, { useEffect, useState, useRef } from "react";
import { Client } from '@stomp/stompjs';
import SockJS from 'sockjs-client';
import '../styles/chat-modal.css';

function isImage(filename) {
  return /\.(jpg|jpeg|png|gif|bmp|webp|svg)$/i.test(filename);
}

function getFileTypeLabel(filename) {
  const ext = filename.split('.').pop().toLowerCase();
  if (["pdf"].includes(ext)) return "View PDF";
  if (["doc","docx"].includes(ext)) return "View Word Document";
  if (["xls","xlsx"].includes(ext)) return "View Excel Spreadsheet";
  if (["ppt","pptx"].includes(ext)) return "View PowerPoint";
  return "Download Attachment";
}

function renderMessageContent(content) {
  if (!content) return null;
  // Regex to match URLs in text
  const urlRegex = /(https?:\/\/[^\s]+)/g;
  const parts = content.split(urlRegex);
  return parts.map((part, i) =>
    urlRegex.test(part)
      ? <a key={i} href={part} target="_blank" rel="noopener noreferrer" className="text-blue-300 underline">{part}</a>
      : <span key={i}>{part}</span>
  );
}

export default function ChatModal({
  open, onClose, currentUser, otherUser, task, showHeader = true
}) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [attachment, setAttachment] = useState(null);
  const [otherTyping, setOtherTyping] = useState(false);
  const fileInputRef = useRef();
  const messagesEndRef = useRef(null);
  const stompRef = useRef(null);
  const typingTimeoutRef = useRef(null);

  useEffect(() => {
    if (!open) return;
    fetch(`http://localhost:8080/api/messages/thread?taskId=${task.id}&userA=${currentUser.id}&userB=${otherUser.id}`)
      .then(res => res.json())
      .then(setMessages);

    // Setup STOMP client for real-time chat
    const minId = Math.min(currentUser.id, otherUser.id);
    const maxId = Math.max(currentUser.id, otherUser.id);
    const topic = `/topic/chat/${task.id}-${minId}-${maxId}`;
    const typingTopic = `/topic/chat/${task.id}-${minId}-${maxId}/typing`;
    const socket = new SockJS('http://localhost:8080/ws/notifications');
    const stompClient = new Client({
      webSocketFactory: () => socket,
      reconnectDelay: 5000,
      debug: () => {},
    });
    stompRef.current = stompClient;
    stompClient.onConnect = () => {
      stompClient.subscribe(topic, (message) => {
        const msg = JSON.parse(message.body);
        setMessages(m => {
          // Mark as read if recipient is current user and not already read
          if (msg.recipient.id === currentUser.id && !msg.read) {
            fetch(`http://localhost:8080/api/messages/${msg.id}/read`, { method: 'POST' });
          }
          return [...m, msg];
        });
      });
      stompClient.subscribe(typingTopic, (msg) => {
        const typing = JSON.parse(msg.body);
        if (typing.userId === otherUser.id) {
          setOtherTyping(true);
          if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
          typingTimeoutRef.current = setTimeout(() => setOtherTyping(false), 2000);
        }
      });
    };
    stompClient.activate();

    return () => {
      stompClient.deactivate();
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    };
  }, [open, currentUser, otherUser, task]);

  // Auto-scroll to latest message
  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  const sendMessage = async () => {
    if (!input && !attachment) return;
    let attachmentUrl = null;
    if (attachment) {
      // Upload the file to backend
      const formData = new FormData();
      formData.append('file', attachment);
      try {
        const uploadRes = await fetch('http://localhost:8080/api/files/upload', {
          method: 'POST',
          body: formData
        });
        if (!uploadRes.ok) {
          alert('File upload failed');
          return;
        }
        attachmentUrl = await uploadRes.text();
        if (attachmentUrl.startsWith('"') && attachmentUrl.endsWith('"')) {
          attachmentUrl = attachmentUrl.substring(1, attachmentUrl.length - 1);
        }
      } catch (err) {
        alert('File upload failed');
        return;
      }
    }
    const res = await fetch(`http://localhost:8080/api/messages/send?senderId=${currentUser.id}&recipientId=${otherUser.id}&taskId=${task.id}&content=${encodeURIComponent(input)}${attachmentUrl ? `&attachmentUrl=${encodeURIComponent(attachmentUrl)}` : ''}`,
      { method: 'POST' });
    if (res.ok) {
      setInput("");
      setAttachment(null);
      if (fileInputRef.current) fileInputRef.current.value = "";
    }
  };

  if (!open) return null;
  return (
    <div className="chat-modal-overlay">
      <div className="chat-modal-box">
        {showHeader && (
          <div className="chat-modal-header">
            <span className="chat-modal-title">{otherUser.username}</span>
            <button className="chat-modal-close" onClick={onClose}>✕</button>
          </div>
        )}
        <div className="chat-modal-messages">
          {messages.length === 0 ? (
            <div className="text-violet-400 text-center mt-16">No messages yet.</div>
          ) : (
            messages.map(msg => (
              <div key={msg.id} className={`chat-modal-message ${msg.sender.id === currentUser.id ? 'me' : 'other'}`}>
                <div className={`chat-modal-bubble${msg.sender.id !== currentUser.id ? ' other' : ''}`}>
                  {renderMessageContent(msg.content)}
                  {msg.attachmentUrl && (
                    isImage(msg.attachmentUrl)
                      ? (
                        <a href={`http://localhost:8080/${msg.attachmentUrl.replace(/^\/uploads\//, '')}`} target="_blank" rel="noopener noreferrer" className="block mt-1">
                          <img
                            src={`http://localhost:8080/${msg.attachmentUrl.replace(/^\/uploads\//, '')}`}
                            alt="attachment"
                            className="max-h-32 rounded border mb-1"
                            style={{maxWidth:'150px'}}
                          />
                          <span className="text-xs underline">View Image</span>
                        </a>
                      )
                      : (
                        <a className="block text-xs underline mt-1" href={`http://localhost:8080/${msg.attachmentUrl.replace(/^\/uploads\//, '')}`} target="_blank" rel="noopener noreferrer">
                          {getFileTypeLabel(msg.attachmentUrl)}
                        </a>
                      )
                  )}
                  <div className="chat-modal-time">{new Date(msg.sentAt).toLocaleTimeString()} {msg.sender.id === currentUser.id && (msg.read ? '✓✓' : '✓')}</div>
                </div>
              </div>
            ))
          )}
          {otherTyping && <div className="chat-modal-typing">{otherUser.username} is typing...</div>}
          <div ref={messagesEndRef}></div>
        </div>
        <div className="chat-modal-input-row">
          <input
            type="text"
            className="chat-modal-input"
            placeholder="Type a message..."
            value={input}
            onChange={e => {
              setInput(e.target.value);
              // Send typing event
              if (stompRef.current && stompRef.current.connected) {
                const minId = Math.min(currentUser.id, otherUser.id);
                const maxId = Math.max(currentUser.id, otherUser.id);
                const typingTopic = `/topic/chat/${task.id}-${minId}-${maxId}/typing`;
                stompRef.current.publish({
                  destination: typingTopic,
                  body: JSON.stringify({ userId: currentUser.id })
                });
              }
            }}
            onKeyDown={e => { if (e.key === 'Enter') sendMessage(); }}
          />
          <input
            type="file"
            ref={fileInputRef}
            onChange={e => setAttachment(e.target.files[0])}
            className="chat-modal-file"
          />
          <button
            className="chat-modal-send"
            onClick={sendMessage}
          >Send</button>
        </div>
      </div>
    </div>
  );
}
